# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector
from sys import argv

# Enable local_infile in MySQL config and Python connector
mydb = mysql.connector.connect(
    host="localhost",
    user="your_username",
    password="your_password",
    database="your_database"
)

mycursor = mydb.cursor()
mycursor.execute("SET GLOBAL local_infile=1")

if len(argv) < 2:
    print("Please provide a file path as an argument.")
else:
    file_path = argv[1]
    query = "LOAD DATA INFILE '{}' INTO TABLE your_table_name FIELDS TERMINATED BY ',' OPTIONALLY ENCLOSED BY '\"' LINES TERMINATED BY '\n' IGNORE 1 ROWS;"
    mycursor.execute(query.format(file_path))
    print("Data import completed.")

mydb.commit()
mycursor.close()